'use strict';

const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = 'payment_events';

async function consumePaymentEvents() {
    let connection;
    try {
        connection = await amqp.connect(RABBITMQ_URL);
        const channel = await connection.createChannel();

        await channel.assertQueue(QUEUE_NAME, {
            durable: true
        });

        console.log(`[*] Waiting for messages in ${QUEUE_NAME}. To exit press CTRL+C`);

        channel.consume(QUEUE_NAME, async (msg) => {
            if (msg !== null) {
                const content = JSON.parse(msg.content.toString());
                console.log(`[x] Received message:`);
                console.log(content);

                try {
                    // Simulate payment processing logic
                    await processPayment(content);
                    console.log(`[x] Payment processed successfully for transactionId: ${content.transactionId}`);
                    channel.ack(msg); // Acknowledge the message
                } catch (error) {
                    console.error(`[!] Error processing payment for transactionId: ${content.transactionId}`, error);
                    // Decide whether to NACK and re-queue or simply acknowledge to move past the problematic message
                    // For now, we'll NACK and re-queue to try again later or move to a dead-letter queue if configured.
                    channel.nack(msg, false, true); // NACK, don't re-queue for all, re-queue this message
                }
            }
        }, {
            noAck: false // Important: We will manually acknowledge messages
        });

    } catch (error) {
        console.error('Failed to connect to RabbitMQ or consume messages:', error);
        if (connection) {
            await connection.close();
        }
        process.exit(1);
    }
}

/**
 * Simulates payment processing logic.
 * In a real application, this would interact with payment gateways, databases, etc.
 * @param {Object} paymentEvent - The payment event object from RabbitMQ.
 * @param {string} paymentEvent.transactionId - Unique ID for the transaction.
 * @param {number} paymentEvent.amount - Amount to be paid.
 * @param {string} paymentEvent.currency - Currency of the payment.
 * @param {string} paymentEvent.cardNumber - Last 4 digits or tokenized card info.
 * @param {string} paymentEvent.paymentMethod - e.g., 'credit_card', 'paypal', 'bank_transfer'.
 */
async function processPayment(paymentEvent) {
    return new Promise((resolve, reject) => {
        // Simulate an asynchronous payment gateway call or database operation
        const processingTime = Math.random() * 3000 + 500; // 0.5 to 3.5 seconds
        setTimeout(() => {
            if (paymentEvent.amount > 10000) {
                // Simulate a failure for large amounts
                console.warn(`[!] Simulated payment failure for transactionId: ${paymentEvent.transactionId} (amount too high)`);
                return reject(new Error('Payment amount exceeds limit'));
            }
            console.log(`Processing payment for ${paymentEvent.amount} ${paymentEvent.currency} (Transaction ID: ${paymentEvent.transactionId})`);
            // In a real scenario, here you'd integrate with actual payment processors
            // and update your database based on success/failure.
            resolve({
                status: 'success',
                transactionId: paymentEvent.transactionId,
                processedAt: new Date().toISOString()
            });
        }, processingTime);
    });
}

